121	export function registerTools(server: McpServer, runtime: RouterRuntime): void {
122	  const consultService = new ConsultService(runtime, runtime.locks);
123	
124	  server.registerTool(
125	    "claude_sessions_list",
126	    {
127	      title: "List Claude sessions",
128	      description: "Returns known Claude sessions for a project.",
129	      inputSchema: sessionsListInput
130	    },
131	    async (input) => {
132	      const projectId = resolveProjectId(input.project_id, runtime.cwd);
133	      runtime.db.applyLifecycle(projectId);
134	      const sessions = runtime.db.listSessions(
135	        projectId,
136	        input.include_dormant,
137	        input.include_archived,
138	        input.include_orphaned
139	      );
140	
141	      return jsonToolResult({
142	        project_id: projectId,
143	        sessions
144	      });
145	    }
146	  );
147	
148	  server.registerTool(
149	    "claude_session_inspect",
150	    {
151	      title: "Inspect Claude session",
152	      description: "Returns the full registry view of a session without invoking Claude.",
153	      inputSchema: sessionInspectInput
154	    },
155	    async (input) => {
156	      const projectId = resolveProjectId(input.project_id, runtime.cwd);
157	      const inspection = runtime.db.inspectSession(input.session_id, input.recent_events_limit);
158	      if (!inspection) {
159	        return jsonToolResult(
160	          errorPayload(ERROR_CODES.SESSION_NOT_FOUND, SPEC_ERROR_MESSAGES[ERROR_CODES.SESSION_NOT_FOUND]),
161	          true
162	        );
163	      }
164	
165	      if (inspection.session.project_id !== projectId) {
166	        return jsonToolResult(
167	          errorPayload(ERROR_CODES.PROJECT_MISMATCH, SPEC_ERROR_MESSAGES[ERROR_CODES.PROJECT_MISMATCH]),
168	          true
169	        );
170	      }
171	
172	      return jsonToolResult({
173	        session: inspection.session,
174	        recent_events: inspection.recentEvents,
175	        recent_events_note: "truncated; default returns up to 10 events, hard max 50"
176	      });
177	    }
178	  );
179	
180	  server.registerTool(
181	    "claude_consult",
182	    {
183	      title: "Consult Claude",
184	      description: "Calls Claude in an auto-routed or selected persistent session.",
185	      inputSchema: consultInput
186	    },
187	    async (input) => {
188	      const projectId = resolveProjectId(input.project_id, runtime.cwd);
189	      const result = await consultService.consult({
190	        projectId,
191	        sessionId: input.session_id,
192	        topicHint: input.topic_hint,
193	        trigger: input.trigger,
194	        task: input.task,
195	        relevantCode: input.relevant_code,
196	        question: input.question
