284	      description:
285	        "Stores a static_verified factsheet, or runs no-tools LLM verification when verification_mode is llm.",
286	      inputSchema: clusterPrepareInput
287	    },
288	    async (input) => {
289	      const projectId = resolveProjectId(input.project_id, runtime.cwd);
290	      let profileSelection: ProfileSelection | null = null;
291	      if ((input.verification_mode ?? "static") === "llm" && runtime.degradedMode) {
292	        const diagnosis = diagnoseClaudeFailure(runtime.degradedReason);
293	        return jsonToolResult(
294	          errorPayload(ERROR_CODES.CLAUDE_INCOMPATIBLE, SPEC_ERROR_MESSAGES[ERROR_CODES.CLAUDE_INCOMPATIBLE], {
295	            cluster_id: input.cluster_id,
296	            reason: diagnosis.reason,
297	            category: diagnosis.category,
298	            operator_action: diagnosis.operator_action
299	          }),
300	          true
301	        );
302	      }
303	      try {
304	        if ((input.verification_mode ?? "static") === "llm") {
305	          const availability = await runtime.getProfileAvailability();
306	          profileSelection = pickProfile(input.llm_verifier_profile ?? "focused", availability);
307	          if (profileSelection.selected === "agent") {
308	            throw new Error("LLM verifier cannot use agent profile");
309	          }
310	        }
311	
312	        const result = await prepareCluster(runtime.db, runtime.cwd, runtime.claude, {
313	          projectId,
314	          clusterId: input.cluster_id,
315	          name: input.name ?? undefined,
316	          description: input.description ?? undefined,
317	          toolProfileDefault: input.tool_profile_default,
318	          factsheet: input.factsheet as FactsheetInput,
319	          sourceSessionId: input.source_session_id,
320	          gitRev: input.git_rev,
321	          verificationMode: input.verification_mode ?? "static",
322	          llmVerifierProfile: profileSelection?.selected === "bare" ? "bare" : "focused"
323	        });
324	        if (profileSelection?.downgraded) {
325	          runtime.db.logClusterEvent({
326	            clusterId: input.cluster_id,
327	            projectId,
328	            eventType: "tool_profile_downgraded",
329	            details: profileSelection
330	          });
331	        }
332	
333	        return jsonToolResult({
334	          project_id: projectId,
335	          ...(profileSelection ? { profile_selection: profileSelection } : {}),
336	          ...result
337	        });
338	      } catch (error: unknown) {
339	        const reason = error instanceof Error ? error.message : String(error);
340	        const code = reason.includes("belongs to project")
341	          ? ERROR_CODES.CLUSTER_PROJECT_MISMATCH
342	          : reason.includes("Claude") || reason.includes("Command failed")
343	            ? ERROR_CODES.CLAUDE_INVOCATION_FAILED
344	          : ERROR_CODES.CLUSTER_FACTSHEET_INVALID;
345	        return jsonToolResult(
346	          errorPayload(code, SPEC_ERROR_MESSAGES[code], {
347	            cluster_id: input.cluster_id,
348	            reason
349	          }),
350	          true
351	        );
352	      }
353	    }
354	  );
355	
356	  server.registerTool(
357	    "cluster_get",
358	    {
359	      title: "Get cluster",
360	      description: "Returns cluster metadata and the current static_verified or llm_verified factsheet without invoking Claude.",
361	      inputSchema: clusterGetInput
362	    },
363	    async (input) => {
364	      const projectId = resolveProjectId(input.project_id, runtime.cwd);
365	      const cluster = runtime.db.getClusterById(input.cluster_id);
366	      if (!cluster) {
367	        return jsonToolResult(
368	          errorPayload(ERROR_CODES.CLUSTER_NOT_FOUND, SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_NOT_FOUND], {
369	            cluster_id: input.cluster_id
370	          }),
371	          true
372	        );
373	      }
374	      if (cluster.project_id !== projectId) {
375	        return jsonToolResult(
376	          errorPayload(
377	            ERROR_CODES.CLUSTER_PROJECT_MISMATCH,
378	            SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_PROJECT_MISMATCH],
379	            { cluster_id: input.cluster_id }
380	          ),
381	          true
382	        );
383	      }
384	
385	      const factsheet = input.include_factsheet ? runtime.db.getCurrentClusterFactsheet(input.cluster_id) : null;
386	      return jsonToolResult({
387	        project_id: projectId,
388	        cluster,
389	        current_factsheet: factsheet ? serializeFactsheet(factsheet) : null,
390	        file_hashes: factsheet ? runtime.db.listClusterFileHashes(factsheet.id) : []
391	      });
392	    }
393	  );
394	
395	  server.registerTool(
396	    "cluster_consult",
397	    {
398	      title: "Consult cluster",
399	      description: "Consults Claude with a verified cluster factsheet inline. Fork support is not implemented in this phase.",
400	      inputSchema: clusterConsultInput
401	    },
402	    async (input) => {
403	      const projectId = resolveProjectId(input.project_id, runtime.cwd);
404	      if (runtime.degradedMode) {
405	        const diagnosis = diagnoseClaudeFailure(runtime.degradedReason);
406	        return jsonToolResult(
407	          errorPayload(ERROR_CODES.CLAUDE_INCOMPATIBLE, SPEC_ERROR_MESSAGES[ERROR_CODES.CLAUDE_INCOMPATIBLE], {
408	            cluster_id: input.cluster_id,
409	            reason: diagnosis.reason,
410	            category: diagnosis.category,
411	            operator_action: diagnosis.operator_action
412	          }),
413	          true
414	        );
415	      }
416	
417	      const availability = await runtime.getProfileAvailability();
418	      const result = await consultCluster(runtime.db, runtime.cwd, runtime.claude, availability, {
419	        projectId,
420	        clusterId: input.cluster_id,
421	        question: input.question,
422	        toolProfile: input.tool_profile,
423	        allowStaticFactsheet: input.allow_static_factsheet
424	      });
425	
426	      return jsonToolResult(
427	        {
428	          project_id: projectId,
429	          ...result
430	        },
431	        "error" in result
432	      );
433	    }
434	  );
435	
436	  server.registerTool(
437	    "cluster_refresh",
438	    {
439	      title: "Refresh cluster",
440	      description: "Revalidates the latest cluster factsheet by checking scoped evidence file hashes and selectors.",
441	      inputSchema: clusterRefreshInput
442	    },
443	    async (input) => {
444	      const projectId = resolveProjectId(input.project_id, runtime.cwd);
445	      const result = refreshCluster(runtime.db, runtime.cwd, {
446	        projectId,
447	        clusterId: input.cluster_id,
448	        mode: input.mode
449	      });
450	
451	      return jsonToolResult(
452	        {
453	          project_id: projectId,
454	          ...result
455	        },
456	        "error" in result
457	      );
458	    }
459	  );
460	
461	  server.registerTool(
462	    "cluster_list",
463	    {
464	      title: "List clusters",
465	      description: "Lists cluster cache entries for a project without invoking Claude.",
466	      inputSchema: clusterListInput
467	    },
468	    async (input) => {
469	      const projectId = resolveProjectId(input.project_id, runtime.cwd);
470	      const clusters = runtime.db.listClusters(projectId, input.include_archived).map((cluster) => {
471	        const factsheet = runtime.db.getCurrentClusterFactsheet(cluster.id);
472	        return {
473	          ...cluster,
474	          current_factsheet: factsheet
475	            ? {
476	                id: factsheet.id,
477	                version: factsheet.version,
478	                status: factsheet.status,
479	                git_rev: factsheet.git_rev,
480	                generated_at: factsheet.generated_at,
481	                verified_at: factsheet.verified_at,
482	                fact_count: factsheetFactCount(factsheet)
483	              }
484	            : null
485	        };
486	      });
487	
488	      return jsonToolResult({
489	        project_id: projectId,
490	        clusters
491	      });
492	    }
493	  );
494	}
495	
496	function serializeFactsheet(factsheet: ClusterFactsheetRecord): object {
497	  return {
498	    id: factsheet.id,
499	    cluster_id: factsheet.cluster_id,
500	    version: factsheet.version,
501	    source_session_id: factsheet.source_session_id,
502	    baseline_session_id: factsheet.baseline_session_id,
503	    git_rev: factsheet.git_rev,
504	    generated_at: factsheet.generated_at,
505	    verified_at: factsheet.verified_at,
506	    status: factsheet.status,
507	    content: parseFactsheetContent(factsheet)
508	  };
509	}
510	
511	function factsheetFactCount(factsheet: ClusterFactsheetRecord): number {
512	  const content = parseFactsheetContent(factsheet);
513	  return Array.isArray(content.facts) ? content.facts.length : 0;
514	}
515	
516	function parseFactsheetContent(factsheet: ClusterFactsheetRecord): Record<string, unknown> {
517	  try {
518	    const parsed = JSON.parse(factsheet.content_json) as unknown;
519	    if (typeof parsed === "object" && parsed !== null && !Array.isArray(parsed)) {
520	      return parsed as Record<string, unknown>;
521	    }
522	  } catch {
523	    return {};
524	  }
525	  return {};
526	}
527

